## 1. Cache Line Optimization

```cpp
// BAD: False sharing between threads
struct alignas(64) BadCounter {
    std::atomic<int64_t> value;  // Shares cache line
};

// GOOD: Proper padding to avoid false sharing
struct alignas(64) Counter {
    std::atomic<int64_t> value;
    char padding[64 - sizeof(std::atomic<int64_t>)];
};

// Cache-friendly data layout
// BAD: Array of Structures (AOS)
struct Particle {
    float x, y, z;    // Position
    float vx, vy, vz; // Velocity
    float mass;
};
std::vector<Particle> particles; // Bad for iteration on single property

// GOOD: Structure of Arrays (SOA)
struct Particles {
    std::vector<float> x, y, z;       // Positions
    std::vector<float> vx, vy, vz;    // Velocities
    std::vector<float> mass;
};
// x is contiguous in memory, SIMD-friendly
```

## 2. Branch Prediction Optimization

```cpp
// BAD: Branch-heavy code (misprediction penalty ~15-20 cycles)
int sum = 0;
for (int i = 0; i < n; i++) {
    if (data[i] > threshold) {  // 50% misprediction rate
        sum += data[i];
    }
}

// GOOD: Branchless with conditional move
int sum = 0;
for (int i = 0; i < n; i++) {
    sum += (data[i] > threshold) ? data[i] : 0;  // CMOV instruction
}

// GOOD: Sort data to improve branch prediction
std::sort(data.begin(), data.end());  // Now branches are predictable
for (int i = 0; i < n; i++) {
    if (data[i] > threshold) {
        sum += data[i];  // Predictable: first N are below, rest above
    }
}

// GOOD: Use bit manipulation for branchless
count = __builtin_popcount(mask);  // Hardware popcount, no branches
