## 3. SIMD Vectorization

```cpp
#include <immintrin.h>

// Scalar version
void add_arrays(float* a, float* b, float* c, size_t n) {
    for (size_t i = 0; i < n; i++) {
        c[i] = a[i] + b[i];
    }
}

// AVX2 SIMD version (8 floats at once)
void add_arrays_simd(float* a, float* b, float* c, size_t n) {
    size_t i = 0;
    for (; i + 8 <= n; i += 8) {
        __m256 va = _mm256_loadu_ps(&a[i]);
        __m256 vb = _mm256_loadu_ps(&b[i]);
        __m256 vc = _mm256_add_ps(va, vb);
        _mm256_storeu_ps(&c[i], vc);
    }
    // Handle remainder
    for (; i < n; i++) {
        c[i] = a[i] + b[i];
    }
}

// SIMD dot product
float dot_product_simd(float* a, float* b, size_t n) {
    __m256 sum = _mm256_setzero_ps();
    size_t i = 0;
    for (; i + 8 <= n; i += 8) {
        __m256 va = _mm256_loadu_ps(&a[i]);
        __m256 vb = _mm256_loadu_ps(&b[i]);
        sum = _mm256_fmadd_ps(va, vb, sum);  // FMA
    }
    // Horizontal sum
    alignas(32) float temp[8];
    _mm256_store_ps(temp, sum);
    float result = 0;
    for (int j = 0; j < 8; j++) result += temp[j];
    // Handle remainder
    for (; i < n; i++) result += a[i] * b[i];
    return result;
}
