## 5. CPU Architecture Detection

```cpp
#include <cpuid.h>

struct CpuFeatures {
    bool sse4_2;
    bool avx2;
    bool avx512f;
    bool bmi2;
    bool popcnt;
    bool lzcnt;
};

CpuFeatures detect_cpu() {
    CpuFeatures features = {};
    unsigned int eax, ebx, ecx, edx;

    __cpuid(1, eax, ebx, ecx, edx);
    features.sse4_2 = (ecx >> 20) & 1;

    __cpuid_count(7, 0, eax, ebx, ecx, edx);
    features.avx2 = (ebx >> 5) & 1;
    features.avx512f = (ebx >> 16) & 1;
    features.bmi2 = (ebx >> 8) & 1;

    __cpuid(1, eax, ebx, ecx, edx);
    features.popcnt = (ecx >> 23) & 1;
    features.lzcnt = (ebx >> 5) & 1;

    return features;
}

// Runtime dispatch
void process_data(float* data, size_t n) {
    static const CpuFeatures cpu = detect_cpu();

    if (cpu.avx512f && n >= 16) {
        process_data_avx512(data, n);
    } else if (cpu.avx2 && n >= 8) {
        process_data_avx2(data, n);
    } else if (cpu.sse4_2 && n >= 4) {
        process_data_sse42(data, n);
    } else {
        process_data_scalar(data, n);
    }
}
