## 6. Memory Access Patterns

```cpp
// Row-major traversal (cache-friendly for C/C++)
for (int i = 0; i < ROWS; i++) {
    for (int j = 0; j < COLS; j++) {
        matrix[i][j] = 0; // Sequential memory access
    }
}

// Column-major traversal (cache-unfriendly)
for (int j = 0; j < COLS; j++) {
    for (int i = 0; i < ROWS; i++) {
        matrix[i][j] = 0; // Strided memory access
    }
}

// Block tiling for cache reuse
const int BLOCK = 64;
for (int ii = 0; ii < ROWS; ii += BLOCK) {
    for (int jj = 0; jj < COLS; jj += BLOCK) {
        for (int i = ii; i < std::min(ii + BLOCK, ROWS); i++) {
            for (int j = jj; j < std::min(jj + BLOCK, COLS); j++) {
                matrix[i][j] = 0; // Fits in L1 cache
            }
        }
    }
}
