            "class": "class {name} {{\npublic:\n{methods}\n\nprivate:\n{fields}\n}};\n",
            "function": "{return_type} {name}({params}) {{\n{body}\n}}\n",
        },
        "go": {
            "file": "// {description}\n\npackage {package}\n\n{imports}\n\n{body}\n",
            "struct": "type {name} struct {{\n{fields}\n}}\n",
            "function": "func {name}({params}) {return_type} {{\n{body}\n}}\n",
        },
        "qml": {
            "file": "// {description}\n\nimport QtQuick 2.15\nimport QtQuick.Controls 2.15\nimport QtQuick.Layouts 1.15\n\n{body}\n",
            "component": "{type} {{\n    id: root\n\n{properties}\n\n{signals}\n\n{methods}\n}}\n",
        },
    }

    def generate_file(self, filepath: str, content: str, language: str, optimize: bool = True) -> str:
        """Generate a code file with optional optimization."""
        path = Path(filepath)
        path.parent.mkdir(parents=True, exist_ok=True)

        if optimize:
            content = self._optimize_content(content, language)

        with open(path, 'w', encoding='utf-8') as f:
            f.write(content)

        return str(path.absolute())

    def generate_from_template(self, template_type: str, language: str, data: dict) -> str:
        """Generate code from a template."""
        template = self.TEMPLATES.get(language, {}).get(template_type, "")
        return template.format(**data)

    def _optimize_content(self, content: str, language: str) -> str:
        """Apply language-specific optimizations."""
        if language == "python":
            content = self._optimize_python(content)
        elif language in ["typescript", "javascript"]:
            content = self._optimize_typescript(content)
        elif language == "rust":
            content = self._optimize_rust(content)
        elif language in ["cpp", "c"]:
            content = self._optimize_cpp(content)
        return content

    def _optimize_python(self, content: str) -> str:
        lines = content.split('\n')
        optimized = []
        for line in lines:
            if 'import *' in line:
                continue  # Remove wildcard imports
            optimized.append(line)
        return '\n'.join(optimized)

    def _optimize_typescript(self, content: str) -> str:
        return content.replace('any', 'unknown', 1)  # Prefer unknown over any

    def _optimize_rust(self, content: str) -> str:
        return content

    def _optimize_cpp(self, content: str) -> str:
        return content

    def batch_generate(self, files: list[dict]) -> list[str]:
        """Generate multiple files at once."""
        paths = []
        for file_spec in files:
            path = self.generate_file(
                filepath=file_spec["path"],
                content=file_spec["content"],
                language=file_spec.get("language", "text"),
                optimize=file_spec.get("optimize", True),
            )
            paths.append(path)
        return paths


