# chat_server.py
import asyncio
import json
import websockets
from dataclasses import dataclass, field
from datetime import datetime
from typing import Dict, Set
from collections import defaultdict


@dataclass
class Client:
    ws: websockets.WebSocketServerProtocol
    user_id: str
    username: str
    rooms: Set[str] = field(default_factory=set)
    last_typing: float = 0


@dataclass
class Message:
    room: str
    user_id: str
    username: str
    content: str
    timestamp: str
    msg_type: str = "message"


class ChatServer:
    def __init__(self):
        self.clients: Dict[str, Client] = {}
        self.rooms: Dict[str, Set[str]] = defaultdict(set)
        self.history: Dict[str, list] = defaultdict(list)
        self.max_history = 100

    async def register(self, ws, user_id: str, username: str):
        client = Client(ws=ws, user_id=user_id, username=username)
        self.clients[user_id] = client
        await self.broadcast({"type": "user_joined", "user_id": user_id, "username": username})
        print(f"{username} connected ({user_id})")

    async def unregister(self, user_id: str):
        if user_id in self.clients:
            client = self.clients.pop(user_id)
            for room in client.rooms:
                self.rooms[room].discard(user_id)
            await self.broadcast({"type": "user_left", "user_id": user_id})
            print(f"{client.username} disconnected")

    async def handle_message(self, user_id: str, data: dict):
        msg_type = data.get("type")
        if msg_type == "join_room":
            await self.join_room(user_id, data["room"])
        elif msg_type == "leave_room":
            await self.leave_room(user_id, data["room"])
        elif msg_type == "message":
            await self.send_message(user_id, data)
        elif msg_type == "typing":
            await self.handle_typing(user_id, data)
        elif msg_type == "get_history":
            await self.get_history(user_id, data["room"])
        elif msg_type == "list_rooms":
            await self.list_rooms(user_id)
        elif msg_type == "list_users":
            await self.list_users(user_id)

    async def join_room(self, user_id: str, room: str):
        client = self.clients.get(user_id)
        if not client:
            return
        client.rooms.add(room)
        self.rooms[room].add(user_id)
        await client.ws.send(json.dumps({"type": "room_joined", "room": room}))
        await self.broadcast_to_room(room, {
            "type": "user_joined_room",
            "room": room,
            "user_id": user_id,
            "username": client.username,
        }, exclude={user_id})

    async def leave_room(self, user_id: str, room: str):
        client = self.clients.get(user_id)
        if not client:
            return
        client.rooms.discard(room)
        self.rooms[room].discard(user_id)
        await self.broadcast_to_room(room, {
            "type": "user_left_room",
            "room": room,
            "user_id": user_id,
            "username": client.username,
        })

    async def send_message(self, user_id: str, data: dict):
        client = self.clients.get(user_id)
        if not client:
            return
        room = data.get("room", "general")
        if room not in client.rooms:
            await self.join_room(user_id, room)
        msg = Message(
            room=room,
            user_id=user_id,
            username=client.username,
            content=data["content"],
            timestamp=datetime.utcnow().isoformat(),
        )
        self.history[room].append(msg.__dict__)
        if len(self.history[room]) > self.max_history:
            self.history[room] = self.history[room][-self.max_history:]
        await self.broadcast_to_room(room, {
            "type": "message",
            "room": room,
            "user_id": user_id,
            "username": client.username,
            "content": data["content"],
            "timestamp": msg.timestamp,
        })

    async def handle_typing(self, user_id: str, data: dict):
        client = self.clients.get(user_id)
        if not client:
            return
        room = data.get("room", "general")
        await self.broadcast_to_room(room, {
            "type": "typing",
            "user_id": user_id,
            "username": client.username,
            "room": room,
            "is_typing": data.get("is_typing", True),
        }, exclude={user_id})

    async def get_history(self, user_id: str, room: str):
        client = self.clients.get(user_id)
        if not client:
            return
        history = self.history.get(room, [])[-50:]
        await client.ws.send(json.dumps({"type": "history", "room": room, "messages": history}))

    async def list_rooms(self, user_id: str):
        client = self.clients.get(user_id)
        if not client:
            return
        rooms = [{"name": r, "members": len(members)} for r, members in self.rooms.items()]
        await client.ws.send(json.dumps({"type": "room_list", "rooms": rooms}))

    async def list_users(self, user_id: str):
        client = self.clients.get(user_id)
        if not client:
            return
        users = [{"user_id": uid, "username": c.username} for uid, c in self.clients.items()]
        await client.ws.send(json.dumps({"type": "user_list", "users": users}))

    async def broadcast(self, data: dict):
        message = json.dumps(data)
        for client in self.clients.values():
            try:
                await client.ws.send(message)
            except websockets.ConnectionClosed:
                pass

    async def broadcast_to_room(self, room: str, data: dict, exclude: Set[str] = None):
        exclude = exclude or set()
        message = json.dumps(data)
        for user_id in self.rooms.get(room, set()):
            if user_id not in exclude and user_id in self.clients:
                try:
                    await self.clients[user_id].ws.send(message)
                except websockets.ConnectionClosed:
                    pass


async def handler(ws, path):
    server = ChatServer()
    user_id = None
    try:
        async for message in ws:
            data = json.loads(message)
            if data.get("type") == "auth":
                user_id = data.get("user_id", str(id(ws)))
                await server.register(ws, user_id, data.get("username", "Anonymous"))
            elif user_id:
                await server.handle_message(user_id, data)
    except websockets.ConnectionClosed:
        pass
    finally:
        if user_id:
            await server.unregister(user_id)


async def main():
    server = ChatServer()
    async with websockets.serve(handler, "0.0.0.0", 8765):
        print("Chat server running on ws://0.0.0.0:8765")
        await asyncio.Future()  # run forever


if __name__ == "__main__":
    asyncio.run(main())
