// chat_client.js
class ChatClient {
  constructor(url, username) {
    this.url = url;
    this.username = username;
    this.ws = null;
    this.userId = crypto.randomUUID();
    this.handlers = new Map();
    this.connected = false;
    this.reconnectAttempts = 0;
    this.maxReconnectAttempts = 10;
    this.typingTimeout = null;
  }

  connect() {
    return new Promise((resolve, reject) => {
      this.ws = new WebSocket(this.url);

      this.ws.onopen = () => {
        this.connected = true;
        this.reconnectAttempts = 0;
        this.send({ type: 'auth', user_id: this.userId, username: this.username });
        this.emit('connected');
        resolve();
      };

      this.ws.onmessage = (event) => {
        const data = JSON.parse(event.data);
        this.handleMessage(data);
      };

      this.ws.onclose = () => {
        this.connected = false;
        this.emit('disconnected');
        this.reconnect();
      };

      this.ws.onerror = (error) => {
        reject(error);
      };
    });
  }

  reconnect() {
    if (this.reconnectAttempts >= this.maxReconnectAttempts) return;
    this.reconnectAttempts++;
    const delay = Math.min(1000 * Math.pow(2, this.reconnectAttempts), 30000);
    setTimeout(() => this.connect(), delay);
  }

  send(data) {
    if (this.ws?.readyState === WebSocket.OPEN) {
      this.ws.send(JSON.stringify(data));
    }
  }

  joinRoom(room) {
    this.send({ type: 'join_room', room });
  }

  leaveRoom(room) {
    this.send({ type: 'leave_room', room });
  }

  sendMessage(room, content) {
    this.send({ type: 'message', room, content });
  }

  setTyping(room, isTyping) {
    this.send({ type: 'typing', room, is_typing: isTyping });
  }

  startTyping(room) {
    this.setTyping(room, true);
    clearTimeout(this.typingTimeout);
    this.typingTimeout = setTimeout(() => this.setTyping(room, false), 3000);
  }

  getHistory(room) {
    this.send({ type: 'get_history', room });
  }

  listRooms() {
    this.send({ type: 'list_rooms' });
  }

  listUsers() {
    this.send({ type: 'list_users' });
  }

  on(event, handler) {
    if (!this.handlers.has(event)) this.handlers.set(event, []);
    this.handlers.get(event).push(handler);
  }

  emit(event, data) {
    const handlers = this.handlers.get(event) || [];
    handlers.forEach(h => h(data));
  }

  handleMessage(data) {
    this.emit(data.type, data);
  }

  disconnect() {
    clearTimeout(this.typingTimeout);
    this.ws?.close();
  }
}

