#[derive(Debug, Clone, Serialize, Deserialize)]
struct ChatMessage {
    room: String,
    user_id: String,
    username: String,
    content: String,
    timestamp: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct RoomInfo {
    name: String,
    members: usize,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct UserInfo {
    user_id: String,
    username: String,
}

struct ChatServer {
    clients: Arc<RwLock<HashMap<String, ClientInfo>>>,
    rooms: Arc<RwLock<HashMap<String, HashSet<String>>>>,
    history: Arc<RwLock<HashMap<String, Vec<ChatMessage>>>>,
    tx: broadcast::Sender<String>,
}

struct ClientInfo {
    user_id: String,
    username: String,
    rooms: HashSet<String>,
    addr: std::net::SocketAddr,
}

impl ChatServer {
    fn new() -> Self {
        let (tx, _) = broadcast::channel(1000);
        Self {
            clients: Arc::new(RwLock::new(HashMap::new())),
            rooms: Arc::new(RwLock::new(HashMap::new())),
            history: Arc::new(RwLock::new(HashMap::new())),
            tx,
        }
    }

    async fn handle_client(&self, stream: TcpStream, addr: std::net::SocketAddr) {
        let (reader, mut writer) = stream.into_split();
        let mut lines = BufReader::new(reader).lines();
        let mut rx = self.tx.subscribe();
        let user_id = Uuid::new_v4().to_string();

        let mut client_info: Option<ClientInfo> = None;

        loop {
            tokio::select! {
                line = lines.next_line() => {
                    match line {
                        Ok(Some(line)) => {
                            if let Ok(msg) = serde_json::from_str::<ClientMessage>(&line) {
                                match msg {
                                    ClientMessage::Auth { user_id: uid, username } => {
                                        let info = ClientInfo {
                                            user_id: uid.clone(),
                                            username: username.clone(),
                                            rooms: HashSet::new(),
                                            addr,
                                        };
                                        self.clients.write().await.insert(uid.clone(), info.clone());
                                        client_info = Some(info);
                                        let msg = serde_json::json!({"type": "user_joined", "user_id": uid, "username": username});
                                        let _ = self.tx.send(msg.to_string());
                                    }
                                    ClientMessage::JoinRoom { room } => {
                                        if let Some(ref mut info) = client_info {
                                            info.rooms.insert(room.clone());
                                            self.rooms.write().await.entry(room.clone()).or_default().insert(info.user_id.clone());
                                            let resp = serde_json::json!({"type": "room_joined", "room": room});
                                            let _ = writer.write_all(format!("{}\n", resp).as_bytes()).await;
                                        }
                                    }
                                    ClientMessage::SendMessage { room, content } => {
                                        if let Some(ref info) = client_info {
                                            let chat_msg = ChatMessage {
                                                room: room.clone(),
                                                user_id: info.user_id.clone(),
                                                username: info.username.clone(),
                                                content,
                                                timestamp: Utc::now().to_rfc3339(),
                                            };
                                            self.history.write().await.entry(room.clone()).or_default().push(chat_msg.clone());
                                            let resp = serde_json::json!({"type": "message", "room": room, "user_id": info.user_id, "username": info.username, "content": chat_msg.content, "timestamp": chat_msg.timestamp});
                                            let _ = self.tx.send(resp.to_string());
                                        }
                                    }
                                    _ => {}
                                }
                            }
                        }
                        _ => break,
                    }
                }
                msg = rx.recv() => {
                    if let Ok(msg) = msg {
                        let _ = writer.write_all(format!("{}\n", msg).as_bytes()).await;
                    }
                }
            }
        }

        // Cleanup
        if let Some(info) = client_info {
            self.clients.write().await.remove(&info.user_id);
            for room in &info.rooms {
                if let Some(members) = self.rooms.write().await.get_mut(room) {
                    members.remove(&info.user_id);
                }
            }
            let msg = serde_json::json!({"type": "user_left", "user_id": info.user_id});
            let _ = self.tx.send(msg.to_string());
        }
    }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let server = ChatServer::new();
    let listener = TcpListener::bind("0.0.0.0:8765").await?;
    println!("Chat server running on 0.0.0.0:8765");

    loop {
        let (stream, addr) = listener.accept().await?;
        let server = server.clone();
        tokio::spawn(async move {
            server.handle_client(stream, addr).await;
        });
    }
}
